import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"5、教皇【V】","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/5、教皇【V】 .md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/5、教皇【V】 .md"}'),_={name:"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/5、教皇【V】 .md"};function d(p,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"_5、教皇【v】",tabindex:"-1"},[s("5、教皇【V】 "),e("a",{class:"header-anchor",href:"#_5、教皇【v】","aria-label":'Permalink to "5、教皇【V】"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD:灵魂蓝调011")])])],-1),o('<h1 id="教皇" tabindex="-1">教皇 <a class="header-anchor" href="#教皇" aria-label="Permalink to &quot;教皇&quot;">​</a></h1><p>法皇之绿</p><p>A+4800（替身价格）<br> 替身外貌：<br> 主体绿色。全身布满像哈密瓜般的细密纹路，穿着浅白色盔甲，脸上戴着嘴套。常态为人型，但其实是由无数的触手合体而成的。因此可以将全身分解成超长的触手来攻击，也有将体液凝固之后发射出的招数【绿宝石水花】。<br> 替身数据：<br> 破坏力C 速度B（偏斜防御） 射程A 持续力B 精密动作性C 成长性D<br> 替身对应主属性：决心<br> 替身能力：<br> 身体操纵:法皇之绿可以将自己的身体分解成触手,然后钻进单个目标或多个目标的体内操纵其神经，得以操纵目标，这个能力的射程范围为【决心×10】米，标准动作发动并维持，目标以强韧豁免对替身使者的替身使用检定，不造成伤害，对抗失败会被法皇之绿完全控制，每轮可以尝试再进行一次对抗以挣脱这个效果，持续至其脱离触手或维持结束，视为A级创伤来源的支配效果。</p><p>绿宝石水花：将自身的体液凝固之后形成像绿宝石一样的固体发射，这个能力的射程范围为【决心×20】米，能以一个标准动作对射程范围内单个或多个目标攻击，这种攻击方式具有【连射特性】。</p><p>法皇的结界：以一个移动动作发动并维持将替身身体分解成触手后形成结界攻击，这个能力的射程和覆盖范围为【决心×5】米， 在这个范围内的敌人在面对法皇之绿的控制或是绿宝石水花时会承受【决心÷2】点环境减值。</p><p>半径20m绿宝石水花：在形成法皇的结界后才能使用的能力，全力对结界内的单一目标无死角地发射绿宝石，这次替身使用检定会获得【决心】点环境加值。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=r(_,[["render",d]]);export{f as __pageData,m as default};
